# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import os
import pymysql


def get_db_connection():
    """Create and return a database connection using environment variables."""
    connection = pymysql.connect(
        host=os.environ.get('DB_HOST', 'localhost'),
        port=int(os.environ.get('DB_PORT', 3306)),
        user=os.environ.get('DB_USER', 'root'),
        password=os.environ.get('DB_PASSWORD', ''),
        database=os.environ.get('DB_NAME', 'products_db'),
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=5,
        read_timeout=30,
        write_timeout=30
    )
    return connection


def build_search_query(params):
    """
    Dynamically build a SQL query based on search parameters.
    
    Supported parameters:
    - keyword: search in product name and description
    - category: filter by category
    - min_price: minimum price filter
    - max_price: maximum price filter
    - brand: filter by brand
    - in_stock: filter by stock availability (true/false)
    - sort_by: field to sort by (name, price, created_at, rating)
    - sort_order: ASC or DESC
    - page: page number for pagination
    - page_size: number of results per page
    - tags: comma-separated list of tags
    - min_rating: minimum rating filter
    - max_rating: maximum rating filter
    - sku: exact SKU match
    - created_after: filter products created after this date (YYYY-MM-DD)
    - created_before: filter products created before this date (YYYY-MM-DD)
    """
    base_query = "SELECT * FROM products"
    count_query = "SELECT COUNT(*) as total FROM products"
    conditions = []
    values = []

    # Keyword search in name and description
    if params.get('keyword'):
        keyword = f"%{params['keyword']}%"
        conditions.append("(name LIKE %s OR description LIKE %s)")
        values.extend([keyword, keyword])

    # Category filter
    if params.get('category'):
        conditions.append("category = %s")
        values.append(params['category'])

    # Brand filter
    if params.get('brand'):
        conditions.append("brand = %s")
        values.append(params['brand'])

    # SKU exact match
    if params.get('sku'):
        conditions.append("sku = %s")
        values.append(params['sku'])

    # Price range filters
    if params.get('min_price'):
        try:
            min_price = float(params['min_price'])
            conditions.append("price >= %s")
            values.append(min_price)
        except (ValueError, TypeError):
            pass

    if params.get('max_price'):
        try:
            max_price = float(params['max_price'])
            conditions.append("price <= %s")
            values.append(max_price)
        except (ValueError, TypeError):
            pass

    # Rating range filters
    if params.get('min_rating'):
        try:
            min_rating = float(params['min_rating'])
            conditions.append("rating >= %s")
            values.append(min_rating)
        except (ValueError, TypeError):
            pass

    if params.get('max_rating'):
        try:
            max_rating = float(params['max_rating'])
            conditions.append("rating <= %s")
            values.append(max_rating)
        except (ValueError, TypeError):
            pass

    # Stock availability filter
    if params.get('in_stock') is not None:
        in_stock = str(params['in_stock']).lower()
        if in_stock in ('true', '1', 'yes'):
            conditions.append("stock_quantity > 0")
        elif in_stock in ('false', '0', 'no'):
            conditions.append("stock_quantity = 0")

    # Tags filter (comma-separated)
    if params.get('tags'):
        tags = [tag.strip() for tag in params['tags'].split(',') if tag.strip()]
        if tags:
            tag_conditions = []
            for tag in tags:
                tag_conditions.append("FIND_IN_SET(%s, tags) > 0")
                values.append(tag)
            conditions.append(f"({' OR '.join(tag_conditions)})")

    # Date range filters
    if params.get('created_after'):
        conditions.append("created_at >= %s")
        values.append(params['created_after'])

    if params.get('created_before'):
        conditions.append("created_at <= %s")
        values.append(params['created_before'])

    # Build WHERE clause
    where_clause = ""
    if conditions:
        where_clause = " WHERE " + " AND ".join(conditions)

    count_query += where_clause

    # Sorting
    allowed_sort_fields = {'name', 'price', 'created_at', 'rating', 'stock_quantity', 'brand', 'category'}
    sort_by = params.get('sort_by', 'created_at')
    if sort_by not in allowed_sort_fields:
        sort_by = 'created_at'

    sort_order = params.get('sort_order', 'DESC').upper()
    if sort_order not in ('ASC', 'DESC'):
        sort_order = 'DESC'

    order_clause = f" ORDER BY {sort_by} {sort_order}"

    # Pagination
    try:
        page = max(1, int(params.get('page', 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        page_size = min(100, max(1, int(params.get('page_size', 20))))
    except (ValueError, TypeError):
        page_size = 20

    offset = (page - 1) * page_size
    limit_clause = f" LIMIT %s OFFSET %s"

    full_query = base_query + where_clause + order_clause + limit_clause
    query_values = values.copy()
    query_values.extend([page_size, offset])

    return {
        'query': full_query,
        'count_query': count_query,
        'values': query_values,
        'count_values': values,
        'page': page,
        'page_size': page_size
    }


def extract_params(event):
    """Extract search parameters from the API Gateway event."""
    params = {}

    # Get query string parameters
    query_params = event.get('queryStringParameters') or {}
    params.update(query_params)

    # Also support POST body parameters for complex searches
    if event.get('httpMethod', '').upper() == 'POST' and event.get('body'):
        try:
            body = json.loads(event['body'])
            if isinstance(body, dict):
                params.update(body)
        except (json.JSONDecodeError, TypeError):
            pass

    # Support multi-value query string parameters
    multi_params = event.get('multiValueQueryStringParameters') or {}
    for key, value_list in multi_params.items():
        if key == 'tags' and len(value_list) > 1:
            params['tags'] = ','.join(value_list)

    # Also check path parameters for specific product lookups
    path_params = event.get('pathParameters') or {}
    if path_params.get('product_id'):
        params['product_id'] = path_params['product_id']

    return params


def build_response(status_code, body, headers=None):
    """Build a properly formatted API Gateway response."""
    default_headers = {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Headers': 'Content-Type,Authorization',
        'Access-Control-Allow-Methods': 'GET,POST,OPTIONS'
    }
    if headers:
        default_headers.update(headers)

    return {
        'statusCode': status_code,
        'headers': default_headers,
        'body': json.dumps(body, default=str)
    }


def lambda_handler(event, context):
    """
    Main Lambda handler for product search API.
    
    Receives search parameters via API Gateway event and returns
    matching products from RDS MySQL database.
    """
    # Handle CORS preflight
    if event.get('httpMethod', '').upper() == 'OPTIONS':
        return build_response(200, {'message': 'OK'})

    connection = None

    try:
        # Extract search parameters from the event
        params = extract_params(event)

        # Handle direct product lookup by ID
        if params.get('product_id'):
            connection = get_db_connection()
            with connection.cursor() as cursor:
                cursor.execute("SELECT * FROM products WHERE id = %s", (params['product_id'],))
                product = cursor.fetchone()

            if product:
                return build_response(200, {
                    'success': True,
                    'product': product
                })
            else:
                return build_response(404, {
                    'success': False,
                    'message': 'Product not found'
                })

        # Build dynamic search query
        query_data = build_search_query(params)

        connection = get_db_connection()

        with connection.cursor() as cursor:
            # Execute count query for pagination metadata
            cursor.execute(query_data['count_query'], query_data['count_values'])
            count_result = cursor.fetchone()
            total_count = count_result['total'] if count_result else 0

            # Execute search query
            cursor.execute(query_data['query'], query_data['values'])
            products = cursor.fetchall()

        # Calculate pagination metadata
        page = query_data['page']
        page_size = query_data['page_size']
        total_pages = (total_count + page_size - 1) // page_size if total_count > 0 else 0

        response_body = {
            'success': True,
            'data': {
                'products': products,
                'pagination': {
                    'current_page': page,
                    'page_size': page_size,
                    'total_items': total_count,
                    'total_pages': total_pages,
                    'has_next': page < total_pages,
                    'has_previous': page > 1
                }
            },
            'search_params': {k: v for k, v in params.items() if v is not None}
        }

        return build_response(200, response_body)

    except pymysql.MySQLError as e:
        error_code = e.args[0] if e.args else 'Unknown'
        error_message = e.args[1] if len(e.args) > 1 else str(e)

        print(f"Database error [{error_code}]: {error_message}")

        return build_response(500, {
            'success': False,
            'message': 'Database error occurred',
            'error': f"Database error: {error_code}"
        })

    except json.JSONDecodeError:
        return build_response(400, {
            'success': False,
            'message': 'Invalid JSON in request body'
        })

    except Exception as e:
        print(f"Unexpected error: {str(e)}")

        return build_response(500, {
            'success': False,
            'message': 'An internal server error occurred'
        })

    finally:
        if connection:
            try:
                connection.close()
            except Exception:
                pass